class Solution {
public:
    void sortColors(vector<int>& nums) {
        int n = nums.size();
        int p0 = 0, p2 = n - 1; // 不变量：[0,p0) 全为 0，(p2,n-1] 全为 2
        for (int i = 0; i <= p2; ++i) {
            while (i <= p2 && nums[i] == 2) { // 换回来的可能还是 2，必须继续换
                swap(nums[i], nums[p2]);
                --p2;
            }
            if (nums[i] == 0) {
                swap(nums[i], nums[p0]);
                ++p0;
            }
        }
    }
};
